    "<script>\n"
    "const TOKEN_KEY = 'sso_token';\n"
    "const API_BASE = '';\n"
    "\n"
    "function getToken() {\n"
    "  var t = localStorage.getItem(TOKEN_KEY);\n"
    "  if (!t && window.location.hash.length > 1) {\n"
    "    t = decodeURIComponent(window.location.hash.substring(1));\n"
    "    if (t) { localStorage.setItem(TOKEN_KEY, t); window.location.hash = ''; }\n"
    "  }\n"
    "  return t;\n"
    "}\n"
    "\n"
    "function api(path, opts) {\n"
    "  const headers = {'Content-Type': 'application/json'};\n"
    "  const token = getToken();\n"
    "  if (token) headers['Authorization'] = 'Bearer ' + token;\n"
    "  return fetch(API_BASE + path, { ...opts, headers }).then(r => {\n"
    "    if (r.status === 401 && path !== '/api/v1/auth/login') {\n"
    "      logout();\n"
    "      throw new Error('认证过期');\n"
    "    }\n"
    "    return r.json();\n"
    "  });\n"
    "}\n"
    "\n"
    "function toast(msg, type) {\n"
    "  const c = document.getElementById('toastContainer');\n"
    "  const t = document.createElement('div');\n"
    "  t.className = 'toast toast-' + type;\n"
    "  t.textContent = msg;\n"
    "  c.appendChild(t);\n"
    "  setTimeout(() => t.remove(), 3000);\n"
    "}\n"
    "\n"
    "function closeModal(id) { document.getElementById(id).classList.remove('active'); }\n"
    "function showModal(id) { document.getElementById(id).classList.add('active'); }\n"
    "\n"
    "let currentUser = null;\n"
    "\n"
    "function checkAuth() {\n"
    "  const token = getToken();\n"
    "  if (!token) { window.location.href = '/login'; return; }\n"
    "  fetch('/api/v1/auth/verify', {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token:token})}).then(r => {\n"
    "    if (!r.ok) throw new Error('verify failed');\n"
    "    return r.json();\n"
    "  }).then(d => {\n"
    "    if (!d.valid) throw new Error('invalid token');\n"
    "    currentUser = d;\n"
    "    document.getElementById('userInfo').innerHTML = '<strong>' + (d.display_name || d.username) + '</strong><br>' + (d.email || '');\n"
    "  }).catch(() => { window.location.href = '/login'; });\n"
    "}\n"
    "\n"
    "function logout() {\n"
    "  const token = getToken();\n"
    "  if (token) api('/api/v1/auth/logout', {method:'POST'}).catch(() => {});\n"
    "  localStorage.removeItem(TOKEN_KEY);\n"
    "  window.location.href = '/login';\n"
    "}\n"
    "\n"
    "let currentSection = 'users';\n"
    "function switchSection(section) {\n"
    "  currentSection = section;\n"
    "  document.querySelectorAll('.section').forEach(s => s.classList.remove('active'));\n"
    "  document.getElementById('section-' + section).classList.add('active');\n"
    "  document.querySelectorAll('.sidebar nav a').forEach(a => a.classList.remove('active'));\n"
    "  document.querySelector('.sidebar nav a[data-section=\"' + section + '\"]').classList.add('active');\n"
    "  if (section === 'users') loadUsers();\n"
    "  else if (section === 'roles') loadRoles();\n"
    "  else if (section === 'groups') loadGroups();\n"
    "  else if (section === 'policies') loadPolicies();\n"
    "}\n"
    "\n"
    "function htmlEncode(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;'); }\n"
    "\n"
    "// ---- USERS ----\n"
    "let allUsers = [];\n"
    "function loadUsers() {\n"
    "  document.getElementById('userList').innerHTML = '<div class=\"loading\">加载中...</div>';\n"
    "  api('/api/v1/users').then(data => {\n"
    "    if (Array.isArray(data)) { allUsers = data; renderUsers(data); }\n"
    "    else document.getElementById('userList').innerHTML = '<div class=\"empty-state\">加载失败</div>';\n"
    "  }).catch(() => { document.getElementById('userList').innerHTML = '<div class=\"empty-state\">加载失败</div>'; });\n"
    "}\n"
    "\n"
    "function renderUsers(users) {\n"
    "  document.getElementById('userCount').textContent = users.length;\n"
    "  if (users.length === 0) { document.getElementById('userList').innerHTML = '<div class=\"empty-state\">暂无用户</div>'; return; }\n"
    "  let html = '<table><thead><tr><th>ID</th><th>用户名</th><th>显示名称</th><th>邮箱</th><th>状态</th><th>角色</th><th>操作</th></tr></thead><tbody>';\n"
    "  users.forEach(u => {\n"
    "    let statusClass = 'status-active', statusText = '激活';\n"
    "    if (u.status === 0) { statusClass = 'status-disabled'; statusText = '禁用'; }\n"
    "    else if (u.status === 2) { statusClass = 'status-inactive'; statusText = '未激活'; }\n"
    "    const roleTags = (u.roles || []).map(r => '<span class=\"tag\">' + htmlEncode(r.name) + '</span>').join('');\n"
    "    html += '<tr><td>' + u.id + '</td><td><strong>' + htmlEncode(u.username) + '</strong></td><td>' + htmlEncode(u.display_name) + '</td><td>' + htmlEncode(u.email) + '</td>'\n"
    "      + '<td><span class=\"status-badge ' + statusClass + '\">' + statusText + '</span></td>'\n"
    "      + '<td>' + (roleTags || '<span style=\"color:#666\">无</span>') + '</td>'\n"
    "      + '<td><div class=\"btn-group\"><button class=\"btn btn-sm btn-primary\" onclick=\"showAssignRole(' + u.id + ')\">分配角色</button>'\n"
    "      + '<button class=\"btn btn-sm btn-outline\" onclick=\"showEditUser(' + u.id + ')\">编辑</button>'\n"
    "      + '<button class=\"btn btn-sm btn-danger\" onclick=\"deleteUser(' + u.id + ')\">删除</button></div></td></tr>';\n"
    "  });\n"
    "  html += '</tbody></table>';\n"
    "  document.getElementById('userList').innerHTML = html;\n"
    "}\n"
    "\n"
    "function filterUsers() {\n"
    "  const q = document.getElementById('userSearch').value.toLowerCase();\n"
    "  renderUsers(allUsers.filter(u => u.username.toLowerCase().includes(q) || u.display_name.toLowerCase().includes(q) || (u.email && u.email.toLowerCase().includes(q))));\n"
    "}\n"
    "\n"
    "function showCreateUserModal() { showModal('createUserModal'); }\n"
    "\n"
    "function createUser() {\n"
    "  const username = document.getElementById('cuUsername').value.trim();\n"
    "  const password = document.getElementById('cuPassword').value;\n"
    "  if (!username || !password) { toast('用户名和密码为必填项', 'error'); return; }\n"
    "  api('/api/v1/users', {method:'POST', body:JSON.stringify({\n"
    "    username, password,\n"
    "    email: document.getElementById('cuEmail').value.trim(),\n"
    "    display_name: document.getElementById('cuDisplay').value.trim() || username\n"
    "  })}).then(data => {\n"
    "    if (data.created || data.user_id) {\n"
    "      toast('用户 ' + username + ' 创建成功', 'success');\n"
    "      closeModal('createUserModal');\n"
    "      document.getElementById('cuUsername').value = '';\n"
    "      document.getElementById('cuPassword').value = '';\n"
    "      document.getElementById('cuEmail').value = '';\n"
    "      document.getElementById('cuDisplay').value = '';\n"
    "      loadUsers();\n"
    "    } else { toast(data.error || '创建失败', 'error'); }\n"
    "  }).catch(() => toast('创建失败', 'error'));\n"
    "}\n"
    "\n"
    "function showEditUser(userId) {\n"
    "  const user = allUsers.find(u => u.id === userId);\n"
    "  if (!user) return;\n"
    "  document.getElementById('euId').value = userId;\n"
    "  document.getElementById('euEmail').value = user.email || '';\n"
    "  document.getElementById('euDisplay').value = user.display_name || '';\n"
    "  document.getElementById('euStatus').value = user.status;\n"
    "  showModal('editUserModal');\n"
    "}\n"
    "\n"
    "function updateUser() {\n"
    "  const userId = parseInt(document.getElementById('euId').value);\n"
    "  api('/api/v1/users/' + userId, {method:'PUT', body:JSON.stringify({\n"
    "    email: document.getElementById('euEmail').value.trim(),\n"
    "    display_name: document.getElementById('euDisplay').value.trim(),\n"
    "    status: parseInt(document.getElementById('euStatus').value)\n"
    "  })}).then(data => {\n"
    "    if (data.updated) {\n"
    "      toast('用户更新成功', 'success');\n"
    "      closeModal('editUserModal');\n"
    "      loadUsers();\n"
    "    } else { toast(data.error || '更新失败', 'error'); }\n"
    "  }).catch(() => toast('更新失败', 'error'));\n"
    "}\n"
    "\n"
    "function deleteUser(userId) {\n"
    "  if (!confirm('确定要删除用户 #' + userId + ' 吗？')) return;\n"
    "  api('/api/v1/users/' + userId, {method:'DELETE'}).then(data => {\n"
    "    if (data.deleted) {\n"
    "      toast('用户已删除', 'success');\n"
    "      loadUsers();\n"
    "    } else { toast(data.error || '删除失败', 'error'); }\n"
    "  }).catch(() => toast('删除失败', 'error'));\n"
    "}\n"
    "\n"
    "function showAssignRole(userId) {\n"
    "  const user = allUsers.find(u => u.id === userId);\n"
    "  document.getElementById('assignRoleUser').textContent = '用户: ' + (user ? (user.display_name || user.username) : '#' + userId);\n"
    "  document.getElementById('assignRoleSelect').innerHTML = '<option value=\"\">选择角色...</option>';\n"
    "  api('/api/v1/roles').then(roles => {\n"
    "    if (Array.isArray(roles)) {\n"
    "      roles.forEach(r => {\n"
    "        const opt = document.createElement('option');\n"
    "        opt.value = r.id;\n"
    "        opt.textContent = r.name + (r.parent_name ? ' (' + r.parent_name + ')' : '');\n"
    "        document.getElementById('assignRoleSelect').appendChild(opt);\n"
    "      });\n"
    "    }\n"
    "  }).catch(() => {});\n"
    "  document.getElementById('assignRoleSelect').dataset.userId = userId;\n"
    "  showModal('assignRoleModal');\n"
    "}\n"
    "\n"
    "function assignRole() {\n"
    "  const sel = document.getElementById('assignRoleSelect');\n"
    "  const userId = parseInt(sel.dataset.userId);\n"
    "  const roleId = parseInt(sel.value);\n"
    "  if (!roleId) { toast('请选择角色', 'error'); return; }\n"
    "  api('/api/v1/roles/' + roleId + '/assign', {method:'POST', body:JSON.stringify({user_id: userId})})\n"
    "    .then(data => {\n"
    "      if (data.assigned) { toast('角色分配成功', 'success'); closeModal('assignRoleModal'); loadUsers(); }\n"
    "      else { toast(data.error || '分配失败', 'error'); }\n"
    "    }).catch(() => toast('分配失败', 'error'));\n"
    "}\n"
    "\n"
    "// ---- ROLES ----\n"
    "let allRoles = [];\n"
    "function loadRoles() {\n"
    "  document.getElementById('roleList').innerHTML = '<div class=\"loading\">加载中...</div>';\n"
    "  api('/api/v1/roles').then(data => {\n"
    "    if (Array.isArray(data)) {\n"
    "      allRoles = data;\n"
    "      document.getElementById('roleCount').textContent = data.length;\n"
    "      if (data.length === 0) { document.getElementById('roleList').innerHTML = '<div class=\"empty-state\">暂无角色</div>'; return; }\n"
    "      let html = '<table><thead><tr><th>ID</th><th>名称</th><th>描述</th><th>父角色</th><th>创建时间</th><th>操作</th></tr></thead><tbody>';\n"
    "      data.forEach(r => {\n"
    "        html += '<tr><td>' + r.id + '</td><td><strong>' + htmlEncode(r.name) + '</strong></td>'\n"
    "          + '<td>' + htmlEncode(r.description || '-') + '</td>'\n"
    "          + '<td>' + (r.parent_name ? '<span class=\"tag tag-success\">' + htmlEncode(r.parent_name) + '</span>' : '<span style=\"color:#666\">-</span>') + '</td>'\n"
    "          + '<td style=\"color:#666;font-size:12px\">' + new Date(r.created_at).toLocaleString('zh-CN') + '</td>'\n"
    "          + '<td><div class=\"btn-group\"><button class=\"btn btn-sm btn-outline\" onclick=\"showEditRole(' + r.id + ')\">编辑</button>'\n"
    "          + '<button class=\"btn btn-sm btn-danger\" onclick=\"deleteRole(' + r.id + ')\">删除</button></div></td></tr>';\n"
    "      });\n"
    "      html += '</tbody></table>';\n"
    "      document.getElementById('roleList').innerHTML = html;\n"
    "      populateRoleSelects(data);\n"
    "    } else { document.getElementById('roleList').innerHTML = '<div class=\"empty-state\">加载失败</div>'; }\n"
    "  }).catch(() => { document.getElementById('roleList').innerHTML = '<div class=\"empty-state\">加载失败</div>'; });\n"
    "}\n"
    "\n"
    "function populateRoleSelects(roles) {\n"
    "  ['crParent', 'erParent'].forEach(id => {\n"
    "    const sel = document.getElementById(id);\n"
    "    if (!sel) return;\n"
    "    const current = sel.value;\n"
    "    sel.innerHTML = '<option value=\"0\">无（顶级角色）</option>';\n"
    "    if (Array.isArray(roles)) {\n"
    "      roles.forEach(r => { const opt = document.createElement('option'); opt.value = r.id; opt.textContent = r.name + ' (#' + r.id + ')'; sel.appendChild(opt); });\n"
    "    }\n"
    "    sel.value = current;\n"
    "  });\n"
    "}\n"
    "\n"
    "function showCreateRoleModal() {\n"
    "  api('/api/v1/roles').then(roles => { if (Array.isArray(roles)) populateRoleSelects(roles); }).catch(() => {});\n"
    "  showModal('createRoleModal');\n"
    "}\n"
    "\n"
    "function createRole() {\n"
    "  const name = document.getElementById('crName').value.trim();\n"
    "  if (!name) { toast('角色名称为必填项', 'error'); return; }\n"
    "  api('/api/v1/roles', {method:'POST', body:JSON.stringify({\n"
    "    name, description: document.getElementById('crDesc').value.trim(),\n"
    "    parent_role_id: parseInt(document.getElementById('crParent').value) || 0\n"
    "  })}).then(data => {\n"
    "    if (data.created || data.role_id) {\n"
    "      toast('角色 ' + name + ' 创建成功', 'success');\n"
    "      closeModal('createRoleModal');\n"
    "      document.getElementById('crName').value = ''; document.getElementById('crDesc').value = '';\n"
    "      loadRoles();\n"
    "    } else { toast(data.error || '创建失败', 'error'); }\n"
    "  }).catch(() => toast('创建失败', 'error'));\n"
    "}\n"
    "\n"
    "function showEditRole(roleId) {\n"
    "  const role = allRoles.find(r => r.id === roleId);\n"
    "  if (!role) return;\n"
    "  document.getElementById('erId').value = roleId;\n"
    "  document.getElementById('erName').value = role.name;\n"
    "  document.getElementById('erDesc').value = role.description || '';\n"
    "  document.getElementById('erParent').value = role.parent_id || 0;\n"
    "  showModal('editRoleModal');\n"
    "}\n"
    "\n"
    "function updateRole() {\n"
    "  const roleId = parseInt(document.getElementById('erId').value);\n"
    "  api('/api/v1/roles/' + roleId, {method:'PUT', body:JSON.stringify({\n"
    "    name: document.getElementById('erName').value.trim(),\n"
    "    description: document.getElementById('erDesc').value.trim(),\n"
    "    parent_role_id: parseInt(document.getElementById('erParent').value) || 0\n"
    "  })}).then(data => {\n"
    "    if (data.updated) { toast('角色更新成功', 'success'); closeModal('editRoleModal'); loadRoles(); }\n"
    "    else { toast(data.error || '更新失败', 'error'); }\n"
    "  }).catch(() => toast('更新失败', 'error'));\n"
    "}\n"
    "\n"
    "function deleteRole(roleId) {\n"
    "  if (!confirm('确定要删除角色 #' + roleId + ' 吗？')) return;\n"
    "  api('/api/v1/roles/' + roleId, {method:'DELETE'}).then(data => {\n"
    "    if (data.deleted) { toast('角色已删除', 'success'); loadRoles(); }\n"
    "    else { toast(data.error || '删除失败', 'error'); }\n"
    "  }).catch(() => toast('删除失败', 'error'));\n"
    "}\n"
    "\n"
    "// ---- GROUPS ----\n"
    "let allGroups = [];\n"
    "function loadGroups() {\n"
    "  document.getElementById('groupList').innerHTML = '<div class=\"loading\">加载中...</div>';\n"
    "  api('/api/v1/groups').then(data => {\n"
    "    if (Array.isArray(data)) {\n"
    "      allGroups = data;\n"
    "      document.getElementById('groupCount').textContent = data.length;\n"
    "      if (data.length === 0) { document.getElementById('groupList').innerHTML = '<div class=\"empty-state\">暂无分组</div>'; return; }\n"
    "      let html = '<table><thead><tr><th>ID</th><th>名称</th><th>描述</th><th>父分组</th><th>创建时间</th><th>操作</th></tr></thead><tbody>';\n"
    "      data.forEach(g => {\n"
    "        html += '<tr><td>' + g.id + '</td><td><strong>' + htmlEncode(g.name) + '</strong></td>'\n"
    "          + '<td>' + htmlEncode(g.description || '-') + '</td>'\n"
    "          + '<td>' + (g.parent_name ? '<span class=\"tag tag-success\">' + htmlEncode(g.parent_name) + '</span>' : '<span style=\"color:#666\">-</span>') + '</td>'\n"
    "          + '<td style=\"color:#666;font-size:12px\">' + new Date(g.created_at).toLocaleString('zh-CN') + '</td>'\n"
    "          + '<td><div class=\"btn-group\"><button class=\"btn btn-sm btn-outline\" onclick=\"showEditGroup(' + g.id + ')\">编辑</button>'\n"
    "          + '<button class=\"btn btn-sm btn-danger\" onclick=\"deleteGroup(' + g.id + ')\">删除</button></div></td></tr>';\n"
    "      });\n"
    "      html += '</tbody></table>';\n"
    "      document.getElementById('groupList').innerHTML = html;\n"
    "      populateGroupSelects(data);\n"
    "    } else { document.getElementById('groupList').innerHTML = '<div class=\"empty-state\">加载失败</div>'; }\n"
    "  }).catch(() => { document.getElementById('groupList').innerHTML = '<div class=\"empty-state\">加载失败</div>'; });\n"
    "}\n"
    "\n"
    "function populateGroupSelects(groups) {\n"
    "  ['cgParent', 'egParent'].forEach(id => {\n"
    "    const sel = document.getElementById(id);\n"
    "    if (!sel) return;\n"
    "    sel.innerHTML = '<option value=\"0\">无（顶级分组）</option>';\n"
    "    if (Array.isArray(groups)) {\n"
    "      groups.forEach(g => { const opt = document.createElement('option'); opt.value = g.id; opt.textContent = g.name + ' (#' + g.id + ')'; sel.appendChild(opt); });\n"
    "    }\n"
    "  });\n"
    "}\n"
    "\n"
    "function showCreateGroupModal() {\n"
    "  api('/api/v1/groups').then(groups => { if (Array.isArray(groups)) populateGroupSelects(groups); }).catch(() => {});\n"
    "  showModal('createGroupModal');\n"
    "}\n"
    "\n"
    "function createGroup() {\n"
    "  const name = document.getElementById('cgName').value.trim();\n"
    "  if (!name) { toast('分组名称为必填项', 'error'); return; }\n"
    "  api('/api/v1/groups', {method:'POST', body:JSON.stringify({\n"
    "    name, description: document.getElementById('cgDesc').value.trim(),\n"
    "    parent_group_id: parseInt(document.getElementById('cgParent').value) || 0\n"
    "  })}).then(data => {\n"
    "    if (data.created || data.group_id || data.id) {\n"
    "      toast('分组 ' + name + ' 创建成功', 'success');\n"
    "      closeModal('createGroupModal');\n"
    "      document.getElementById('cgName').value = ''; document.getElementById('cgDesc').value = '';\n"
    "      loadGroups();\n"
    "    } else { toast(data.error || '创建失败', 'error'); }\n"
    "  }).catch(() => toast('创建失败', 'error'));\n"
    "}\n"
    "\n"
    "function showEditGroup(groupId) {\n"
    "  const group = allGroups.find(g => g.id === groupId);\n"
    "  if (!group) return;\n"
    "  document.getElementById('egId').value = groupId;\n"
    "  document.getElementById('egName').value = group.name;\n"
    "  document.getElementById('egDesc').value = group.description || '';\n"
    "  document.getElementById('egParent').value = group.parent_id || 0;\n"
    "  showModal('editGroupModal');\n"
    "}\n"
    "\n"
    "function updateGroup() {\n"
    "  const groupId = parseInt(document.getElementById('egId').value);\n"
    "  api('/api/v1/groups/' + groupId, {method:'PUT', body:JSON.stringify({\n"
    "    name: document.getElementById('egName').value.trim(),\n"
    "    description: document.getElementById('egDesc').value.trim(),\n"
    "    parent_group_id: parseInt(document.getElementById('egParent').value) || 0\n"
    "  })}).then(data => {\n"
    "    if (data.updated) { toast('分组更新成功', 'success'); closeModal('editGroupModal'); loadGroups(); }\n"
    "    else { toast(data.error || '更新失败', 'error'); }\n"
    "  }).catch(() => toast('更新失败', 'error'));\n"
    "}\n"
    "\n"
    "function deleteGroup(groupId) {\n"
    "  if (!confirm('确定要删除分组 #' + groupId + ' 吗？')) return;\n"
    "  api('/api/v1/groups/' + groupId, {method:'DELETE'}).then(data => {\n"
    "    if (data.deleted) { toast('分组已删除', 'success'); loadGroups(); }\n"
    "    else { toast(data.error || '删除失败', 'error'); }\n"
    "  }).catch(() => toast('删除失败', 'error'));\n"
    "}\n"
    "\n"
    "// ---- POLICIES ----\n"
    "let allPolicies = [];\n"
    "\n"
    "const STRATEGY_DESC = {\n"
    "  1: '功能权限：控制菜单/按钮/功能级别的访问。示例：admin:*, report:view, user:create',\n"
    "  2: '接口权限：控制 HTTP 方法 + 路径的访问。支持通配符 *。示例：GET /api/v1/users/*',\n"
    "  3: '数据权限：控制资源/字段级别的访问。示例：order 资源的 id,name,amount 字段',\n"
    "  4: '角色权限：检查用户是否拥有指定角色。支持角色层级继承。',\n"
    "  5: '位置权限：基于 IP 地址的访问控制。使用 CIDR 表示法。示例：10.0.0.0/8',\n"
    "  6: '属性权限：基于用户/资源/环境属性的条件判断。支持多种运算符。'\n"
    "};\n"
    "\n"
    "const STRATEGY_TYPE_NAMES = {\n"
    "  1: 'FUNCTIONAL', 2: 'API', 3: 'DATA', 4: 'RBAC', 5: 'LBAC', 6: 'ABAC'\n"
    "};\n"
    "\n"
    "function loadPolicies() {\n"
    "  document.getElementById('policyList').innerHTML = '<div class=\"loading\">加载中...</div>';\n"
    "  api('/api/v1/policies').then(data => {\n"
    "    if (Array.isArray(data)) {\n"
    "      allPolicies = data;\n"
    "      document.getElementById('policyCount').textContent = data.length;\n"
    "      if (data.length === 0) { document.getElementById('policyList').innerHTML = '<div class=\"empty-state\">暂无策略</div>'; return; }\n"
    "      let html = '<table><thead><tr><th>ID</th><th>名称</th><th>类型</th><th>效果</th><th>优先级</th><th>状态</th><th>操作</th></tr></thead><tbody>';\n"
    "      data.forEach(p => {\n"
    "        let effectHtml = p.effect === 1 ? '<span class=\"tag tag-success\">ALLOW</span>' : '<span class=\"tag tag-danger\">DENY</span>';\n"
    "        let statusHtml = p.status === 1 ? '<span class=\"tag tag-success\">启用</span>' : '<span class=\"tag tag-warning\">禁用</span>';\n"
    "        let typeTag = '<span class=\"tag\">' + (STRATEGY_TYPE_NAMES[p.strategy_type] || '?') + '</span>';\n"
    "        if (p.strategy_type === 2) typeTag = '<span class=\"tag tag-warning\">' + (STRATEGY_TYPE_NAMES[p.strategy_type] || '?') + '</span>';\n"
    "        else if (p.strategy_type === 3) typeTag = '<span class=\"tag tag-success\">' + (STRATEGY_TYPE_NAMES[p.strategy_type] || '?') + '</span>';\n"
    "        else if (p.strategy_type >= 4) typeTag = '<span class=\"tag tag-info\">' + (STRATEGY_TYPE_NAMES[p.strategy_type] || '?') + '</span>';\n"
    "        html += '<tr><td>' + p.id + '</td><td><strong>' + htmlEncode(p.name) + '</strong></td>'\n"
    "          + '<td>' + typeTag + '</td>'\n"
    "          + '<td>' + effectHtml + '</td>'\n"
    "          + '<td>' + p.priority + '</td>'\n"
    "          + '<td>' + statusHtml + '</td>'\n"
    "          + '<td><div class=\"btn-group\"><button class=\"btn btn-sm btn-primary\" onclick=\"showAssignPolicy(' + p.id + ')\">分配</button>'\n"
    "          + '<button class=\"btn btn-sm btn-outline\" onclick=\"showEditPolicy(' + p.id + ')\">编辑</button>'\n"
    "          + '<button class=\"btn btn-sm btn-danger\" onclick=\"deletePolicy(' + p.id + ')\">删除</button></div></td></tr>';\n"
    "      });\n"
    "      html += '</tbody></table>';\n"
    "      document.getElementById('policyList').innerHTML = html;\n"
    "    } else { document.getElementById('policyList').innerHTML = '<div class=\"empty-state\">加载失败</div>'; }\n"
    "  }).catch(() => { document.getElementById('policyList').innerHTML = '<div class=\"empty-state\">加载失败</div>'; });\n"
    "}\n"
    "\n"
    "let policyRules = []; // current rule items\n"
    "\n"
    "function onStrategyChange() {\n"
    "  const st = parseInt(document.getElementById('cpStrategy').value);\n"
    "  document.getElementById('strategyDesc').textContent = STRATEGY_DESC[st] || '';\n"
    "  policyRules = [];\n"
    "  renderRuleBuilder(st);\n"
    "  updateRulesPreview();\n"
    "}\n"
    "\n"
    "function renderRuleBuilder(st) {\n"
    "  const builder = document.getElementById('ruleBuilder');\n"
    "  if (st === 1) { // Functional\n"
    "    builder.innerHTML = '<h4>功能规则</h4><div id=\"funcRules\"></div><button class=\"btn btn-sm btn-outline\" onclick=\"addFuncRule()\">+ 添加功能</button>';\n"
    "  } else if (st === 2) { // API\n"
    "    builder.innerHTML = '<h4>接口规则</h4><div id=\"apiRules\"></div><button class=\"btn btn-sm btn-outline\" onclick=\"addApiRule()\">+ 添加接口</button>';\n"
    "  } else if (st === 3) { // Data\n"
    "    builder.innerHTML = '<h4>数据规则</h4><div class=\"form-row\"><div class=\"form-group\"><label>资源类型</label><input id=\"dataResource\" placeholder=\"order\"></div><div class=\"form-group\"><label>范围</label><select id=\"dataScope\"><option value=\"all\">all</option><option value=\"self\">self</option><option value=\"organization\">organization</option></select></div></div><div class=\"form-group\"><label>允许字段（逗号分隔）</label><input id=\"dataFields\" placeholder=\"id,name,email\"></div>';\n"
    "  } else if (st === 4) { // RBAC\n"
    "    builder.innerHTML = '<h4>角色规则</h4><div id=\"rbacRules\"></div><button class=\"btn btn-sm btn-outline\" onclick=\"addRbacRule()\">+ 添加角色</button>';\n"
    "  } else if (st === 5) { // LBAC\n"
    "    builder.innerHTML = '<h4>位置规则</h4><div id=\"lbacRules\"></div><button class=\"btn btn-sm btn-outline\" onclick=\"addLbacRule()\">+ 添加位置</button>';\n"
    "  } else if (st === 6) { // ABAC\n"
    "    builder.innerHTML = '<h4>属性条件</h4><div id=\"abacRules\"></div><button class=\"btn btn-sm btn-outline\" onclick=\"addAbacRule()\">+ 添加条件</button><div class=\"form-group\" style=\"margin-top:10px\"><label>逻辑组合</label><select id=\"abacLogic\"><option value=\"and\">AND（全部满足）</option><option value=\"or\">OR（任一满足）</option></select></div>';\n"
    "  }\n"
    "  renderRuleItems(st);\n"
    "}\n"
    "\n"
    "function addFuncRule() { policyRules.push({code:'', effect:'allow'}); renderRuleItems(1); }\n"
    "function addApiRule() { policyRules.push({method:'GET', path:'', effect:'allow'}); renderRuleItems(2); }\n"
    "function addRbacRule() { policyRules.push({name:'', effect:'allow'}); renderRuleItems(4); }\n"
    "function addLbacRule() { policyRules.push({type:'ip_cidr', value:'', effect:'allow'}); renderRuleItems(5); }\n"
    "function addAbacRule() { policyRules.push({source:'subject', attr:'', op:'eq', value:''}); renderRuleItems(6); }\n"
    "\n"
    "function removeRule(idx) { policyRules.splice(idx, 1); renderRuleItems(parseInt(document.getElementById('cpStrategy').value)); }\n"
    "\n"
    "function renderRuleItems(st) {\n"
    "  let container;\n"
    "  if (st === 1) container = document.getElementById('funcRules');\n"
    "  else if (st === 2) container = document.getElementById('apiRules');\n"
    "  else if (st === 4) container = document.getElementById('rbacRules');\n"
    "  else if (st === 5) container = document.getElementById('lbacRules');\n"
    "  else if (st === 6) container = document.getElementById('abacRules');\n"
    "  else return;\n"
    "\n"
    "  if (!container) return;\n"
    "  if (policyRules.length === 0) { container.innerHTML = '<div style=\"color:#666;font-size:13px;padding:10px 0\">暂无规则，点击上方按钮添加</div>'; updateRulesPreview(); return; }\n"
    "\n"
    "  let html = '';\n"
    "  policyRules.forEach((r, i) => {\n"
    "    html += '<div class=\"rule-item\">';\n"
    "    if (st === 1) {\n"
    "      html += '<div class=\"form-group\"><label>功能代码</label><input value=\"' + htmlEncode(r.code) + '\" onchange=\"policyRules[' + i + '].code=this.value;updateRulesPreview()\" placeholder=\"report:view\"></div>';\n"
    "    } else if (st === 2) {\n"
    "      html += '<div class=\"form-group\"><label>方法</label><input value=\"' + htmlEncode(r.method) + '\" onchange=\"policyRules[' + i + '].method=this.value;updateRulesPreview()\" placeholder=\"GET\" style=\"max-width:80px\"></div>';\n"
    "      html += '<div class=\"form-group\"><label>路径</label><input value=\"' + htmlEncode(r.path) + '\" onchange=\"policyRules[' + i + '].path=this.value;updateRulesPreview()\" placeholder=\"/api/v1/*\"></div>';\n"
    "    } else if (st === 4) {\n"
    "      html += '<div class=\"form-group\"><label>角色名称</label><input value=\"' + htmlEncode(r.name) + '\" onchange=\"policyRules[' + i + '].name=this.value;updateRulesPreview()\" placeholder=\"admin\"></div>';\n"
    "    } else if (st === 5) {\n"
    "      html += '<div class=\"form-group\"><label>类型</label><select onchange=\"policyRules[' + i + '].type=this.value;updateRulesPreview()\"><option value=\"ip_cidr\"' + (r.type==='ip_cidr'?' selected':'') + '>IP CIDR</option></select></div>';\n"
    "      html += '<div class=\"form-group\"><label>范围</label><input value=\"' + htmlEncode(r.value) + '\" onchange=\"policyRules[' + i + '].value=this.value;updateRulesPreview()\" placeholder=\"10.0.0.0/8\"></div>';\n"
    "    } else if (st === 6) {\n"
    "      html += '<div class=\"form-group\"><label>来源</label><select onchange=\"policyRules[' + i + '].source=this.value;updateRulesPreview()\"><option value=\"subject\"' + (r.source==='subject'?' selected':'') + '>subject</option><option value=\"resource\"' + (r.source==='resource'?' selected':'') + '>resource</option><option value=\"environment\"' + (r.source==='environment'?' selected':'') + '>environment</option></select></div>';\n"
    "      html += '<div class=\"form-group\"><label>属性</label><input value=\"' + htmlEncode(r.attr) + '\" onchange=\"policyRules[' + i + '].attr=this.value;updateRulesPreview()\" placeholder=\"department\"></div>';\n"
    "      html += '<div class=\"form-group\"><label>运算符</label><select onchange=\"policyRules[' + i + '].op=this.value;updateRulesPreview()\"><option value=\"eq\"' + (r.op==='eq'?' selected':'') + '>等于</option><option value=\"neq\"' + (r.op==='neq'?' selected':'') + '>不等于</option><option value=\"gt\"' + (r.op==='gt'?' selected':'') + '>大于</option><option value=\"gte\"' + (r.op==='gte'?' selected':'') + '>大于等于</option><option value=\"lt\"' + (r.op==='lt'?' selected':'') + '>小于</option><option value=\"lte\"' + (r.op==='lte'?' selected':'') + '>小于等于</option><option value=\"contains\"' + (r.op==='contains'?' selected':'') + '>包含</option><option value=\"in\"' + (r.op==='in'?' selected':'') + '>在列表中</option></select></div>';\n"
    "      html += '<div class=\"form-group\"><label>值</label><input value=\"' + htmlEncode(r.value) + '\" onchange=\"policyRules[' + i + '].value=this.value;updateRulesPreview()\" placeholder=\"engineering\"></div>';\n"
    "    }\n"
    "    html += '<div class=\"form-group\" style=\"max-width:100px\"><label>效果</label><select onchange=\"policyRules[' + i + '].effect=this.value;updateRulesPreview()\"><option value=\"allow\"' + (r.effect==='allow'?' selected':'') + '>allow</option><option value=\"deny\"' + (r.effect==='deny'?' selected':'') + '>deny</option></select></div>';\n"
    "    html += '<button class=\"btn btn-sm btn-danger\" onclick=\"removeRule(' + i + ')\" style=\"margin-bottom:0\">删除</button>';\n"
    "    html += '</div>';\n"
    "  });\n"
    "  container.innerHTML = html;\n"
    "  updateRulesPreview();\n"
    "}\n"
    "\n"
    "function updateRulesPreview() {\n"
    "  const st = parseInt(document.getElementById('cpStrategy').value);\n"
    "  const effect = document.getElementById('cpEffect').value === '1' ? 'allow' : 'deny';\n"
    "  let rules = {};\n"
    "  if (st === 1) {\n"
    "    rules.functions = policyRules.filter(r => r.code).map(r => ({code: r.code, effect: r.effect}));\n"
    "  } else if (st === 2) {\n"
    "    rules.endpoints = policyRules.filter(r => r.path).map(r => ({method: r.method, path: r.path, effect: r.effect}));\n"
    "  } else if (st === 3) {\n"
    "    const resource = document.getElementById('dataResource').value.trim() || 'resource';\n"
    "    const scope = document.getElementById('dataScope').value;\n"
    "    const fields = document.getElementById('dataFields').value.split(',').filter(f => f.trim()).map(f => f.trim());\n"
    "    rules.rules = [{resource: resource, scope: scope, fields: fields}];\n"
    "    rules.effect = effect;\n"
    "  } else if (st === 4) {\n"
    "    rules.roles = policyRules.filter(r => r.name).map(r => ({name: r.name, effect: r.effect}));\n"
    "  } else if (st === 5) {\n"
    "    rules.locations = policyRules.filter(r => r.value).map(r => ({type: r.type || 'ip_cidr', value: r.value, effect: r.effect}));\n"
    "  } else if (st === 6) {\n"
    "    const logic = document.getElementById('abacLogic') ? document.getElementById('abacLogic').value : 'and';\n"
    "    rules.conditions = policyRules.filter(r => r.attr && r.value).map(r => ({source: r.source, attr: r.attr, op: r.op, value: r.value}));\n"
    "    rules.logic = logic;\n"
    "    rules.effect = effect;\n"
    "  }\n"
    "  document.getElementById('cpRulesPreview').value = JSON.stringify(rules, null, 2);\n"
    "}\n"
    "\n"
    "function showCreatePolicyModal() {\n"
    "  document.getElementById('policyModalTitle').textContent = '创建策略';\n"
    "  document.getElementById('cpId').value = '';\n"
    "  document.getElementById('cpName').value = '';\n"
    "  document.getElementById('cpStrategy').value = '1';\n"
    "  document.getElementById('cpEffect').value = '1';\n"
    "  document.getElementById('cpPriority').value = '50';\n"
    "  document.getElementById('cpStatus').value = '1';\n"
    "  policyRules = [];\n"
    "  onStrategyChange();\n"
    "  showModal('createPolicyModal');\n"
    "}\n"
    "\n"
    "function showEditPolicy(policyId) {\n"
    "  const policy = allPolicies.find(p => p.id === policyId);\n"
    "  if (!policy) return;\n"
    "  document.getElementById('policyModalTitle').textContent = '编辑策略';\n"
    "  document.getElementById('cpId').value = policyId;\n"
    "  document.getElementById('cpName').value = policy.name;\n"
    "  document.getElementById('cpStrategy').value = policy.strategy_type;\n"
    "  document.getElementById('cpEffect').value = policy.effect;\n"
    "  document.getElementById('cpPriority').value = policy.priority;\n"
    "  document.getElementById('cpStatus').value = policy.status;\n"
    "\n"
    "  // Parse existing rules\n"
    "  policyRules = [];\n"
    "  try {\n"
    "    const rules = typeof policy.rules === 'string' ? JSON.parse(policy.rules) : policy.rules;\n"
    "    const st = policy.strategy_type;\n"
    "    if (st === 1 && rules.functions) {\n"
    "      rules.functions.forEach(f => policyRules.push({code: f.code || '', effect: f.effect || 'allow'}));\n"
    "    } else if (st === 2 && rules.endpoints) {\n"
    "      rules.endpoints.forEach(e => policyRules.push({method: e.method || 'GET', path: e.path || '', effect: e.effect || 'allow'}));\n"
    "    } else if (st === 3 && rules.rules) {\n"
    "      const r = rules.rules[0] || {};\n"
    "      setTimeout(() => {\n"
    "        const el = document.getElementById('dataResource'); if (el) el.value = r.resource || '';\n"
    "        const el2 = document.getElementById('dataScope'); if (el2) el2.value = r.scope || 'all';\n"
    "        const el3 = document.getElementById('dataFields'); if (el3) el3.value = (r.fields || []).join(',');\n"
    "        updateRulesPreview();\n"
    "      }, 10);\n"
    "    } else if (st === 4 && rules.roles) {\n"
    "      rules.roles.forEach(r => policyRules.push({name: r.name || '', effect: r.effect || 'allow'}));\n"
    "    } else if (st === 5 && rules.locations) {\n"
    "      rules.locations.forEach(l => policyRules.push({type: l.type || 'ip_cidr', value: l.value || '', effect: l.effect || 'allow'}));\n"
    "    } else if (st === 6 && rules.conditions) {\n"
    "      rules.conditions.forEach(c => policyRules.push({source: c.source || 'subject', attr: c.attr || '', op: c.op || 'eq', value: c.value || ''}));\n"
    "      if (rules.logic) {\n"
    "        setTimeout(() => { const el = document.getElementById('abacLogic'); if (el) el.value = rules.logic; updateRulesPreview(); }, 10);\n"
    "      }\n"
    "    }\n"
    "  } catch(e) {}\n"
    "\n"
    "  onStrategyChange();\n"
    "  showModal('createPolicyModal');\n"
    "}\n"
    "\n"
    "function savePolicy() {\n"
    "  const policyId = document.getElementById('cpId').value;\n"
    "  const name = document.getElementById('cpName').value.trim();\n"
    "  if (!name) { toast('策略名称为必填项', 'error'); return; }\n"
    "  const rulesStr = document.getElementById('cpRulesPreview').value.trim();\n"
    "  if (!rulesStr) { toast('请至少添加一条规则', 'error'); return; }\n"
    "\n"
    "  const payload = {\n"
    "    name,\n"
    "    strategy_type: parseInt(document.getElementById('cpStrategy').value),\n"
    "    effect: parseInt(document.getElementById('cpEffect').value),\n"
    "    priority: parseInt(document.getElementById('cpPriority').value) || 50,\n"
    "    status: parseInt(document.getElementById('cpStatus').value),\n"
    "    rules: rulesStr\n"
    "  };\n"
    "\n"
    "  const url = policyId ? '/api/v1/policies/' + policyId : '/api/v1/policies';\n"
    "  const method = policyId ? 'PUT' : 'POST';\n"
    "\n"
    "  api(url, {method, body: JSON.stringify(payload)}).then(data => {\n"
    "    if (data.created || data.policy_id || data.updated) {\n"
    "      toast(policyId ? '策略更新成功' : '策略 ' + name + ' 创建成功', 'success');\n"
    "      closeModal('createPolicyModal');\n"
    "      loadPolicies();\n"
    "    } else { toast(data.error || '保存失败', 'error'); }\n"
    "  }).catch(() => toast('保存失败', 'error'));\n"
    "}\n"
    "\n"
    "function deletePolicy(policyId) {\n"
    "  if (!confirm('确定要删除策略 #' + policyId + ' 吗？')) return;\n"
    "  api('/api/v1/policies/' + policyId, {method:'DELETE'}).then(data => {\n"
    "    if (data.deleted) { toast('策略已删除', 'success'); loadPolicies(); }\n"
    "    else { toast(data.error || '删除失败', 'error'); }\n"
    "  }).catch(() => toast('删除失败', 'error'));\n"
    "}\n"
    "\n"
    "function showAssignPolicy(policyId) {\n"
    "  document.getElementById('assignPolicyInfo').textContent = '策略 ID: ' + policyId;\n"
    "  document.getElementById('apTargetId').value = '';\n"
    "  document.getElementById('assignPolicyInfo').dataset.policyId = policyId;\n"
    "  showModal('assignPolicyModal');\n"
    "}\n"
    "\n"
    "function assignPolicy() {\n"
    "  const policyId = parseInt(document.getElementById('assignPolicyInfo').dataset.policyId);\n"
    "  const targetType = parseInt(document.getElementById('apTargetType').value);\n"
    "  const targetId = parseInt(document.getElementById('apTargetId').value);\n"
    "  if (!targetId) { toast('请输入目标 ID', 'error'); return; }\n"
    "  api('/api/v1/policies/' + policyId + '/assign', {method:'POST', body:JSON.stringify({target_type: targetType, target_id: targetId})})\n"
    "    .then(data => {\n"
    "      if (data.assigned) { toast('策略分配成功', 'success'); closeModal('assignPolicyModal'); }\n"
    "      else { toast(data.error || '分配失败', 'error'); }\n"
    "    }).catch(() => toast('分配失败', 'error'));\n"
    "}\n"
    "\n"
    "// Init\n"
    "checkAuth();\n"
    "loadUsers();\n"
    "</script>\n"
    "</body>\n"
    "</html>\n"
    "";

#endif /* SSO_ADMIN_PAGE_H */
